package com.google.gson.protobuf.generated;

import static org.mockito.Mockito.*;

import com.google.protobuf.ExtensionRegistryLite;
import com.google.protobuf.ExtensionRegistry;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class AnnotationsTest {

  @Test
  void registerAllExtensions_withExtensionRegistryLite_callsAddTwice() {
    ExtensionRegistryLite registryLite = Mockito.mock(ExtensionRegistryLite.class);

    Annotations.registerAllExtensions(registryLite);

    verify(registryLite, times(1)).add(Annotations.serializedName);
    verify(registryLite, times(1)).add(Annotations.serializedValue);
    verifyNoMoreInteractions(registryLite);
  }

  @Test
  void registerAllExtensions_withExtensionRegistry_callsAddTwice() {
    ExtensionRegistry registry = Mockito.mock(ExtensionRegistry.class);

    Annotations.registerAllExtensions(registry);

    verify(registry, times(1)).add(Annotations.serializedName);
    verify(registry, times(1)).add(Annotations.serializedValue);
    verifyNoMoreInteractions(registry);
  }
}
